import { useEffect } from 'react';
import { useForm } from 'react-hook-form';
import { zodResolver } from '@hookform/resolvers/zod';
import { z } from 'zod';
import { toast } from 'sonner';
import { StepperDialog, type StepperDialogStep } from '@/components/ui/StepperDialog';
import { ApiError } from '@/lib/api';
import { useDataSourcesQuery } from '@/routes/data-sources/queries';
import { useCreateAiActor } from './queries';

const SCHEMA = z.object({
  name: z.string().trim().min(1, 'Name is required').max(200),
  instructions: z.string().trim().min(1, 'Instructions are required'),
  dataSourceId: z.number({ message: 'Pick a data source' }).int().min(1, 'Pick a data source'),
  additionalContext: z.string(),
  maxQueries: z.number().int().min(1).nullable(),
  activateImmediately: z.boolean(),
});

type FormValues = z.infer<typeof SCHEMA>;

const DEFAULTS: FormValues = {
  name: '',
  instructions: '',
  dataSourceId: 0,
  additionalContext: '',
  maxQueries: null,
  activateImmediately: false,
};

interface CreateAiActorDialogProps {
  open: boolean;
  onClose: () => void;
  initialDataSourceId?: number;
}

export function CreateAiActorDialog({ open, onClose, initialDataSourceId }: CreateAiActorDialogProps) {
  const dsQuery = useDataSourcesQuery();
  const createMutation = useCreateAiActor(initialDataSourceId);

  const form = useForm<FormValues>({
    resolver: zodResolver(SCHEMA),
    defaultValues: { ...DEFAULTS, dataSourceId: initialDataSourceId ?? 0 },
    mode: 'onTouched',
  });
  const { register, reset, watch, formState: { errors } } = form;

  useEffect(() => {
    if (!open) return;
    reset({ ...DEFAULTS, dataSourceId: initialDataSourceId ?? 0 });
  }, [open, reset, initialDataSourceId]);

  const dataSourceId = watch('dataSourceId');

  const dataSources = dsQuery.data?.entries ?? [];

  const onFinish = async () => {
    const v = form.getValues();
    try {
      await createMutation.mutateAsync({
        name: v.name.trim(),
        instructions: v.instructions.trim(),
        dataSourceId: v.dataSourceId,
        additionalContext: v.additionalContext.trim() || null,
        maxQueries: v.maxQueries,
        maxSubscriptionsPerQuery: null,
        createdByUserId: null,
        defaultRecipientIds: null,
        activateImmediately: v.activateImmediately,
      });
      onClose();
    } catch (err) {
      const message = err instanceof ApiError
        ? err.body || `Request failed (${err.status})`
        : err instanceof Error ? err.message : 'Unknown error';
      toast.error(message);
    }
  };

  const steps: StepperDialogStep<FormValues>[] = [
    {
      id: 'basics',
      title: 'Basics',
      description: 'Name and data source.',
      fields: ['name', 'dataSourceId'],
      render: () => (
        <>
          <div className="q-field">
            <label className="q-label" htmlFor="ca-name">
              Name<span className="q-label__req">*</span>
            </label>
            <input
              id="ca-name"
              type="text"
              className={`q-input${errors.name ? ' q-input--error' : ''}`}
              placeholder="Revenue monitor"
              {...register('name')}
            />
            {errors.name && <div className="q-error">{errors.name.message}</div>}
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label className="q-label" htmlFor="ca-ds">
              Data source<span className="q-label__req">*</span>
            </label>
            <select
              id="ca-ds"
              className={`q-input${errors.dataSourceId ? ' q-input--error' : ''}`}
              {...register('dataSourceId', { valueAsNumber: true })}
            >
              <option value={0}>— Select data source —</option>
              {dataSources.map(ds => (
                <option key={ds.id} value={ds.id}>{ds.name}</option>
              ))}
            </select>
            {dsQuery.isLoading && <div className="q-help">Loading data sources…</div>}
            {errors.dataSourceId && <div className="q-error">{errors.dataSourceId.message}</div>}
          </div>
        </>
      ),
    },
    {
      id: 'instructions',
      title: 'Instructions',
      description: 'What should the actor do?',
      fields: ['instructions'],
      render: () => (
        <>
          <div className="q-field">
            <label className="q-label" htmlFor="ca-inst">
              Instructions<span className="q-label__req">*</span>
            </label>
            <textarea
              id="ca-inst"
              rows={8}
              className={`q-input${errors.instructions ? ' q-input--error' : ''}`}
              placeholder="Monitor sales metrics daily. Alert when revenue drops below 10% of the weekly average. Focus on the revenue and orders tables."
              {...register('instructions')}
            />
            <div className="q-help">
              Describe what queries the actor should manage and what conditions to monitor.
            </div>
            {errors.instructions && <div className="q-error">{errors.instructions.message}</div>}
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label className="q-label" htmlFor="ca-ctx">Additional context</label>
            <textarea
              id="ca-ctx"
              rows={3}
              className="q-input"
              placeholder="Optional schema hints, business context, or constraints."
              {...register('additionalContext')}
            />
          </div>
        </>
      ),
    },
    {
      id: 'options',
      title: 'Options',
      description: 'Limits and activation.',
      fields: ['maxQueries', 'activateImmediately'],
      render: () => (
        <>
          <div className="q-field">
            <label className="q-label" htmlFor="ca-max">Max queries (optional)</label>
            <input
              id="ca-max"
              type="number"
              className="q-input"
              placeholder="No limit"
              min={1}
              {...register('maxQueries', {
                setValueAs: v => (v === '' || v == null ? null : Number(v)),
              })}
            />
            <div className="q-help">
              Maximum number of queries this actor can create. Leave blank for no limit.
            </div>
          </div>

          <div className="q-field" style={{ marginTop: 14 }}>
            <label style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
              <input type="checkbox" {...register('activateImmediately')} />
              <span>Activate immediately</span>
            </label>
            <div className="q-help">
              If unchecked, the actor starts in Draft status and must be activated manually.
            </div>
          </div>
        </>
      ),
    },
    {
      id: 'review',
      title: 'Review',
      description: 'Confirm and create.',
      render: () => {
        const v = form.getValues();
        const dsName = dataSources.find(d => d.id === dataSourceId)?.name ?? '—';
        return (
          <dl className="stepper__review">
            <dt>Name</dt>
            <dd>{v.name || <span className="muted">(unset)</span>}</dd>
            <dt>Data source</dt>
            <dd>{dsName}</dd>
            <dt>Max queries</dt>
            <dd>{v.maxQueries ?? <span className="muted">No limit</span>}</dd>
            <dt>Activation</dt>
            <dd>{v.activateImmediately ? 'Active immediately' : 'Draft'}</dd>
          </dl>
        );
      },
    },
  ];

  return (
    <StepperDialog<FormValues>
      open={open}
      onClose={onClose}
      title="New AI actor"
      sub="Create an actor that autonomously manages queries for a data source."
      size="md"
      steps={steps}
      form={form}
      onFinish={onFinish}
      busy={createMutation.isPending}
      finishLabel="Create actor"
    />
  );
}
